// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

// Define the structure for a graph
typedef struct {
    int numNodes;
    int** adjMatrix;
} Graph;

// Function to create a graph
Graph* createGraph(int numNodes) {
    Graph* graph = (Graph*) malloc(sizeof(Graph));
    graph->numNodes = numNodes;
    graph->adjMatrix = (int**) malloc(numNodes * sizeof(int*));
    for (int i = 0; i < numNodes; i++) {
        graph->adjMatrix[i] = (int*) malloc(numNodes * sizeof(int));
        for (int j = 0; j < numNodes; j++) {
            graph->adjMatrix[i][j] = 0;
        }
    }
    return graph;
}

// Function to add an edge to the graph
void addEdge(Graph* graph, int u, int v) {
    graph->adjMatrix[u][v] = 1;
    graph->adjMatrix[v][u] = 1;
}

// Function to check if all invited employees get along
int checkInvitedEmployees(Graph* graph, int* intervals, int numIntervals, int numEmployees) {
    int* visited = (int*) malloc(numEmployees * sizeof(int));
    for (int i = 0; i < numEmployees; i++) {
        visited[i] = 0;
    }
    for (int i = 0; i < numIntervals; i++) {
        for (int j = intervals[i * 2]; j <= intervals[i * 2 + 1]; j++) {
            visited[j] = 1;
        }
    }
    for (int i = 0; i < numEmployees; i++) {
        if (visited[i] == 1) {
            for (int j = 0; j < numEmployees; j++) {
                if (graph->adjMatrix[i][j] == 1 && visited[j] == 1) {
                    return 0;
                }
            }
        }
    }
    return 1;
}

int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        int N, M;
        scanf("%d %d", &N, &M);
        Graph* graph = createGraph(N);
        for (int i = 0; i < M; i++) {
            int u, v;
            scanf("%d %d", &u, &v);
            addEdge(graph, u - 1, v - 1);
        }
        int Q;
        scanf("%d", &Q);
        for (int q = 0; q < Q; q++) {
            int K;
            scanf("%d", &K);
            int* intervals = (int*) malloc(2 * K * sizeof(int));
            for (int i = 0; i < 2 * K; i++) {
                scanf("%d", &intervals[i]);
            }
            if (checkInvitedEmployees(graph, intervals, K, N)) {
                printf("YES\n");
            } else {
                printf("NO\n");
            }
            free(intervals);
        }
        for (int i = 0; i < N; i++) {
            free(graph->adjMatrix[i]);
        }
        free(graph->adjMatrix);
        free(graph);
    }
    return 0;
}

