#include <iostream>
#include <vector>
using namespace std;

// Define the structure for a graph
struct Graph {
    int numNodes;
    vector<vector<int>> adjMatrix;
};

// Function to create a graph
Graph createGraph(int numNodes) {
    Graph graph;
    graph.numNodes = numNodes;
    graph.adjMatrix.resize(numNodes, vector<int>(numNodes, 0));
    return graph;
}

// Function to add an edge to the graph
void addEdge(Graph& graph, int u, int v) {
    graph.adjMatrix[u][v] = 1;
    graph.adjMatrix[v][u] = 1;
}

// Function to check if all invited employees get along
bool checkInvitedEmployees(const Graph& graph, const vector<int>& intervals, int numIntervals, int numEmployees) {
    vector<bool> visited(numEmployees, false);
    for (int i = 0; i < numIntervals; i++) {
        for (int j = intervals[i * 2]; j <= intervals[i * 2 + 1]; j++) {
            visited[j] = true;
        }
    }
    for (int i = 0; i < numEmployees; i++) {
        if (visited[i]) {
            for (int j = 0; j < numEmployees; j++) {
                if (graph.adjMatrix[i][j] && visited[j]) {
                    return false;
                }
            }
        }
    }
    return true;
}

int main() {
    int T;
    cin >> T;
    for (int t = 0; t < T; t++) {
        int N, M;
        cin >> N >> M;
        Graph graph = createGraph(N);
        for (int i = 0; i < M; i++) {
            int u, v;
            cin >> u >> v;
            addEdge(graph, u - 1, v - 1);
        }
        int Q;
        cin >> Q;
        for (int q = 0; q < Q; q++) {
            int K;
            cin >> K;
            vector<int> intervals(2 * K);
            for (int i = 0; i < 2 * K; i++) {
                cin >> intervals[i];
            }
            if (checkInvitedEmployees(graph, intervals, K, N)) {
                cout << "YES" << endl;
            } else {
                cout << "NO" << endl;
            }
        }
    }
    return 0;
}

