        int numNodes;
        int[][] adjMatrix;
        Graph(int numNodes) {
            this.numNodes = numNodes;
            adjMatrix = new int[numNodes][numNodes];
        }
    }
    // Function to add an edge to the graph
    static void addEdge(Graph graph, int u, int v) {
        graph.adjMatrix[u][v] = 1;
        graph.adjMatrix[v][u] = 1;
    }
    // Function to check if all invited employees get along
    static boolean checkInvitedEmployees(Graph graph, int[] intervals, int numIntervals, int numEmployees) {
        boolean[] visited = new boolean[numEmployees];
        for (int i = 0; i < numIntervals; i++) {
            for (int j = intervals[i * 2]; j <= intervals[i * 2 + 1]; j++) {
                visited[j] = true;
            }
        }
        for (int i = 0; i < numEmployees; i++) {
            if (visited[i]) {
                for (int j = 0; j < numEmployees; j++) {
                    if (graph.adjMatrix[i][j] == 1 && visited[j]) {
                        return false;
                    }
                }
            }
        }
        return true;
    }
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        for (int t = 0; t < T; t++) {
            int N = scanner.nextInt();
            int M = scanner.nextInt();
            Graph graph = new Graph(N);
            for (int i = 0; i < M; i++) {
                int u = scanner.nextInt();
                int v = scanner.nextInt();
                addEdge(graph, u - 1, v - 1);
            }
            int Q = scanner.nextInt();
            for (int q = 0; q < Q; q++) {
                int K = scanner.nextInt();
                int[] intervals = new int[2 * K];
                for (int i = 0; i < 2 * K; i++) {
                    intervals[i] = scanner.nextInt();
                }
                if (checkInvitedEmployees(graph, intervals, K, N)) {
                    System.out.println("YES");
                } else {
                    System.out.println("NO");
                }
            }
        }
    }
}

